def position_bias_analysis(
    judgments: list[dict],  # {query_id, left_model, judgment}
) -> dict:
    """Detect position bias: does left-position advantage exist?"""
    left_wins = 0
    right_wins = 0
    ties = 0
    for j in judgments:
        label = j['judgment']
        winner = JUDGMENT_MAP[label][0]
        if winner == 'tie':
            ties += 1
        elif winner == j['left_model']:
            left_wins += 1
        else:
            right_wins += 1
    n_decisive = left_wins + right_wins
    left_bias = left_wins / n_decisive if n_decisive else 0.5
    # Expected 0.5 if no position bias; >0.55 is concerning
    return {
        'left_win_rate': round(left_bias, 4),
        'position_bias': 'high' if abs(left_bias - 0.5) > 0.05 else 'acceptable',
        'left_wins': left_wins, 'right_wins': right_wins, 'ties': ties,
    }

