from collections import defaultdict

def win_rate_by_category(
    judgments: list[dict],  # {query_id, category, winner}
) -> dict:
    cat_wins = defaultdict(lambda: {'a': 0, 'b': 0, 'tie': 0})
    for j in judgments:
        cat = j.get('category', 'unknown')
        w = j['winner']
        cat_wins[cat][w] += 1
    results = {}
    for cat, counts in cat_wins.items():
        total = counts['a'] + counts['b'] + counts['tie']
        wr = (counts['a'] + 0.5 * counts['tie']) / total
        results[cat] = {'win_rate': round(wr, 3), 'n': total}
    return dict(sorted(results.items(), key=lambda x: x[1]['win_rate']))

